using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class InvoiceService
{
    private readonly ApplicationDbContext _context;

    public InvoiceService(ApplicationDbContext context)
    {
        _context = context;
    }

    public async Task<List<Invoice>> GetAllAsync(InvoiceStatus? statusFilter = null)
    {
        var query = _context.Invoices
            .Include(i => i.Patient)
            .Include(i => i.Payments)
            .AsQueryable();

        if (statusFilter.HasValue)
            query = query.Where(i => i.Status == statusFilter.Value);

        return await query.OrderByDescending(i => i.CreatedAt).ToListAsync();
    }

    public async Task<Invoice?> GetByIdAsync(int id)
    {
        return await _context.Invoices
            .Include(i => i.Patient)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .Include(i => i.Appointment)
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task<Invoice> CreateAsync(Invoice invoice)
    {
        invoice.CreatedAt = DateTime.UtcNow;
        invoice.TotalAmount = invoice.LineItems.Sum(li => li.Amount);
        _context.Invoices.Add(invoice);
        await _context.SaveChangesAsync();
        return invoice;
    }

    public async Task RecordPaymentAsync(int invoiceId, decimal amount, PaymentMethod method)
    {
        var invoice = await _context.Invoices
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == invoiceId);

        if (invoice == null) return;

        var payment = new Payment
        {
            InvoiceId = invoiceId,
            Amount = amount,
            PaidAt = DateTime.UtcNow,
            Method = method
        };

        _context.Payments.Add(payment);

        var totalPaid = invoice.Payments.Sum(p => p.Amount) + amount;
        if (totalPaid >= invoice.TotalAmount)
            invoice.Status = InvoiceStatus.Paid;

        await _context.SaveChangesAsync();
    }

    public async Task<int> GetPendingCountAsync()
    {
        return await _context.Invoices
            .Where(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.Overdue)
            .CountAsync();
    }

    public async Task<decimal> GetMonthlyRevenueAsync()
    {
        var startOfMonth = new DateTime(DateTime.Today.Year, DateTime.Today.Month, 1);
        return await _context.Payments
            .Where(p => p.PaidAt >= startOfMonth)
            .SumAsync(p => p.Amount);
    }
}

