@page "/"
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@inject VetClinic.Services.PatientService PatientService
@inject VetClinic.Services.AppointmentService AppointmentService
@inject VetClinic.Services.InvoiceService InvoiceService

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1 class="mb-4">Dashboard</h1>

@if (_loading)
{
    <div class="text-center"><div class="spinner-border" role="status"></div></div>
}
else
{
    <div class="row mb-4">
        <div class="col-md-3">
            <div class="card text-bg-primary mb-3">
                <div class="card-body">
                    <h5 class="card-title">Total Patients</h5>
                    <p class="card-text display-6">@_totalPatients</p>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-success mb-3">
                <div class="card-body">
                    <h5 class="card-title">Today's Appointments</h5>
                    <p class="card-text display-6">@_todayAppointments</p>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-warning mb-3">
                <div class="card-body">
                    <h5 class="card-title">Pending Invoices</h5>
                    <p class="card-text display-6">@_pendingInvoices</p>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-info mb-3">
                <div class="card-body">
                    <h5 class="card-title">Revenue This Month</h5>
                    <p class="card-text display-6">$@_monthlyRevenue.ToString("N2")</p>
                </div>
            </div>
        </div>
    </div>

    <h3>Today's Appointments</h3>
    @if (_todayAppointmentsList.Count == 0)
    {
        <p class="text-muted">No appointments scheduled for today.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped">
                <thead>
                    <tr>
                        <th>Time</th>
                        <th>Patient</th>
                        <th>Reason</th>
                        <th>Status</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var apt in _todayAppointmentsList)
                    {
                        <tr>
                            <td>@apt.ScheduledAt.ToString("h:mm tt")</td>
                            <td>@apt.Patient.Name</td>
                            <td>@apt.Reason</td>
                            <td><span class="badge bg-@GetStatusColor(apt.Status)">@apt.Status</span></td>
                            <td><a href="patients/@apt.PatientId" class="btn btn-sm btn-outline-primary">View Patient</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
}

@code {
    private bool _loading = true;
    private int _totalPatients;
    private int _todayAppointments;
    private int _pendingInvoices;
    private decimal _monthlyRevenue;
    private List<Appointment> _todayAppointmentsList = new();

    protected override async Task OnInitializedAsync()
    {
        _totalPatients = await PatientService.GetTotalCountAsync();
        _todayAppointments = await AppointmentService.GetTodayCountAsync();
        _pendingInvoices = await InvoiceService.GetPendingCountAsync();
        _monthlyRevenue = await InvoiceService.GetMonthlyRevenueAsync();
        _todayAppointmentsList = await AppointmentService.GetTodayAsync();
        _loading = false;
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        _ => "secondary"
    };
}

