@page "/patients"
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@inject VetClinic.Services.PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Patients - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h1>Patients</h1>
    <a href="patients/new" class="btn btn-primary">Add Patient</a>
</div>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search patients..." @bind="_searchQuery" @bind:event="oninput" @bind:after="SearchAsync" />
</div>

@if (_loading)
{
    <div class="text-center"><div class="spinner-border" role="status"></div></div>
}
else if (_patients.Count == 0)
{
    <p class="text-muted">No patients found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Name</th>
                    <th>Species</th>
                    <th>Breed</th>
                    <th>Owner</th>
                    <th>Phone</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var patient in _patients)
                {
                    <tr>
                        <td>@patient.Name</td>
                        <td>@patient.Species</td>
                        <td>@patient.Breed</td>
                        <td>@patient.OwnerName</td>
                        <td>@patient.OwnerPhone</td>
                        <td>
                            <a href="patients/@patient.Id" class="btn btn-sm btn-outline-primary">View</a>
                            <a href="patients/@patient.Id/edit" class="btn btn-sm btn-outline-secondary">Edit</a>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private bool _loading = true;
    private string _searchQuery = string.Empty;
    private List<Patient> _patients = new();

    protected override async Task OnInitializedAsync()
    {
        _patients = await PatientService.GetAllAsync();
        _loading = false;
    }

    private async Task SearchAsync()
    {
        _patients = await PatientService.SearchAsync(_searchQuery);
    }
}

@page "/patients/new"
@page "/patients/{Id:int}/edit"
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@inject VetClinic.Services.PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>@(_isEdit ? "Edit" : "New") Patient - VetClinic</PageTitle>

<h1>@(_isEdit ? "Edit" : "New") Patient</h1>

<div class="row">
    <div class="col-md-8">
        <EditForm Model="_patient" OnValidSubmit="HandleSubmit" FormName="patientForm">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label class="form-label">Name</label>
                <InputText class="form-control" @bind-Value="_patient.Name" />
                <ValidationMessage For="() => _patient.Name" />
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Species</label>
                    <InputText class="form-control" @bind-Value="_patient.Species" />
                    <ValidationMessage For="() => _patient.Species" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Breed</label>
                    <InputText class="form-control" @bind-Value="_patient.Breed" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Date of Birth</label>
                    <InputDate class="form-control" @bind-Value="_patient.DateOfBirth" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Weight (kg)</label>
                    <InputNumber class="form-control" @bind-Value="_patient.Weight" />
                </div>
            </div>

            <hr />
            <h4>Owner Information</h4>

            <div class="mb-3">
                <label class="form-label">Owner Name</label>
                <InputText class="form-control" @bind-Value="_patient.OwnerName" />
                <ValidationMessage For="() => _patient.OwnerName" />
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Phone</label>
                    <InputText class="form-control" @bind-Value="_patient.OwnerPhone" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Email</label>
                    <InputText class="form-control" @bind-Value="_patient.OwnerEmail" />
                </div>
            </div>

            <div class="d-flex gap-2">
                <button type="submit" class="btn btn-primary">@(_isEdit ? "Update" : "Create") Patient</button>
                <a href="patients" class="btn btn-secondary">Cancel</a>
            </div>
        </EditForm>
    </div>
</div>

@code {
    [Parameter] public int? Id { get; set; }

    private Patient _patient = new();
    private bool _isEdit => Id.HasValue;

    protected override async Task OnInitializedAsync()
    {
        if (_isEdit)
        {
            var existing = await PatientService.GetByIdAsync(Id!.Value);
            if (existing != null)
                _patient = existing;
            else
                Navigation.NavigateTo("patients");
        }
    }

    private async Task HandleSubmit()
    {
        if (_isEdit)
            await PatientService.UpdateAsync(_patient);
        else
            await PatientService.CreateAsync(_patient);

        Navigation.NavigateTo("patients");
    }
}

@page "/patients/{Id:int}"
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@inject VetClinic.Services.PatientService PatientService
@inject VetClinic.Services.MedicalRecordService MedicalRecordService
@inject NavigationManager Navigation

<PageTitle>Patient Details - VetClinic</PageTitle>

@if (_patient == null)
{
    <div class="text-center"><div class="spinner-border" role="status"></div></div>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-4">
        <h1>@_patient.Name</h1>
        <a href="patients/@_patient.Id/edit" class="btn btn-outline-primary">Edit Patient</a>
    </div>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="card">
                <div class="card-header"><strong>Patient Information</strong></div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Species</dt>
                        <dd class="col-sm-8">@_patient.Species</dd>
                        <dt class="col-sm-4">Breed</dt>
                        <dd class="col-sm-8">@(_patient.Breed ?? "N/A")</dd>
                        <dt class="col-sm-4">Date of Birth</dt>
                        <dd class="col-sm-8">@(_patient.DateOfBirth?.ToString("MMM d, yyyy") ?? "N/A")</dd>
                        <dt class="col-sm-4">Weight</dt>
                        <dd class="col-sm-8">@(_patient.Weight?.ToString("N1") ?? "N/A") kg</dd>
                    </dl>
                </div>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card">
                <div class="card-header"><strong>Owner Information</strong></div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Name</dt>
                        <dd class="col-sm-8">@_patient.OwnerName</dd>
                        <dt class="col-sm-4">Phone</dt>
                        <dd class="col-sm-8">@(_patient.OwnerPhone ?? "N/A")</dd>
                        <dt class="col-sm-4">Email</dt>
                        <dd class="col-sm-8">@(_patient.OwnerEmail ?? "N/A")</dd>
                    </dl>
                </div>
            </div>
        </div>
    </div>

    <h3>Medical History</h3>
    <button class="btn btn-success mb-3" @onclick="() => _showAddRecord = true">Add Treatment Note</button>

    @if (_showAddRecord)
    {
        <div class="card mb-3">
            <div class="card-body">
                <EditForm Model="_newRecord" OnValidSubmit="AddRecord" FormName="addRecord">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Diagnosis</label>
                            <InputText class="form-control" @bind-Value="_newRecord.Diagnosis" />
                            <ValidationMessage For="() => _newRecord.Diagnosis" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Treatment</label>
                            <InputText class="form-control" @bind-Value="_newRecord.Treatment" />
                            <ValidationMessage For="() => _newRecord.Treatment" />
                        </div>
                    </div>
                    <div class="row">
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Veterinarian</label>
                            <InputText class="form-control" @bind-Value="_newRecord.VeterinarianName" />
                            <ValidationMessage For="() => _newRecord.VeterinarianName" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Date</label>
                            <InputDate class="form-control" @bind-Value="_newRecord.Date" />
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="_newRecord.Notes" />
                    </div>
                    <div class="d-flex gap-2">
                        <button type="submit" class="btn btn-primary">Save</button>
                        <button type="button" class="btn btn-secondary" @onclick="() => _showAddRecord = false">Cancel</button>
                    </div>
                </EditForm>
            </div>
        </div>
    }

    @if (_patient.MedicalRecords.Count == 0)
    {
        <p class="text-muted">No medical records yet.</p>
    }
    else
    {
        <div class="list-group">
            @foreach (var record in _patient.MedicalRecords)
            {
                <div class="list-group-item">
                    <div class="d-flex justify-content-between">
                        <h6 class="mb-1">@record.Diagnosis</h6>
                        <small class="text-muted">@record.Date.ToString("MMM d, yyyy")</small>
                    </div>
                    <p class="mb-1"><strong>Treatment:</strong> @record.Treatment</p>
                    @if (!string.IsNullOrEmpty(record.Notes))
                    {
                        <p class="mb-1"><small>@record.Notes</small></p>
                    }
                    <small class="text-muted">Dr. @record.VeterinarianName</small>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private Patient? _patient;
    private bool _showAddRecord;
    private MedicalRecord _newRecord = new();

    protected override async Task OnInitializedAsync()
    {
        _patient = await PatientService.GetByIdAsync(Id);
        if (_patient == null)
            Navigation.NavigateTo("patients");
        _newRecord.Date = DateTime.Today;
    }

    private async Task AddRecord()
    {
        _newRecord.PatientId = Id;
        await MedicalRecordService.AddAsync(_newRecord);
        _patient = await PatientService.GetByIdAsync(Id);
        _newRecord = new MedicalRecord { Date = DateTime.Today };
        _showAddRecord = false;
    }
}

