@page "/patients/{Id:int}"
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@inject VetClinic.Services.PatientService PatientService
@inject VetClinic.Services.MedicalRecordService MedicalRecordService
@inject NavigationManager Navigation

<PageTitle>Patient Details - VetClinic</PageTitle>

@if (_patient == null)
{
    <div class="text-center"><div class="spinner-border" role="status"></div></div>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-4">
        <h1>@_patient.Name</h1>
        <a href="patients/@_patient.Id/edit" class="btn btn-outline-primary">Edit Patient</a>
    </div>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="card">
                <div class="card-header"><strong>Patient Information</strong></div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Species</dt>
                        <dd class="col-sm-8">@_patient.Species</dd>
                        <dt class="col-sm-4">Breed</dt>
                        <dd class="col-sm-8">@(_patient.Breed ?? "N/A")</dd>
                        <dt class="col-sm-4">Date of Birth</dt>
                        <dd class="col-sm-8">@(_patient.DateOfBirth?.ToString("MMM d, yyyy") ?? "N/A")</dd>
                        <dt class="col-sm-4">Weight</dt>
                        <dd class="col-sm-8">@(_patient.Weight?.ToString("N1") ?? "N/A") kg</dd>
                    </dl>
                </div>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card">
                <div class="card-header"><strong>Owner Information</strong></div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Name</dt>
                        <dd class="col-sm-8">@_patient.OwnerName</dd>
                        <dt class="col-sm-4">Phone</dt>
                        <dd class="col-sm-8">@(_patient.OwnerPhone ?? "N/A")</dd>
                        <dt class="col-sm-4">Email</dt>
                        <dd class="col-sm-8">@(_patient.OwnerEmail ?? "N/A")</dd>
                    </dl>
                </div>
            </div>
        </div>
    </div>

    <h3>Medical History</h3>
    <button class="btn btn-success mb-3" @onclick="() => _showAddRecord = true">Add Treatment Note</button>

    @if (_showAddRecord)
    {
        <div class="card mb-3">
            <div class="card-body">
                <EditForm Model="_newRecord" OnValidSubmit="AddRecord" FormName="addRecord">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Diagnosis</label>
                            <InputText class="form-control" @bind-Value="_newRecord.Diagnosis" />
                            <ValidationMessage For="() => _newRecord.Diagnosis" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Treatment</label>
                            <InputText class="form-control" @bind-Value="_newRecord.Treatment" />
                            <ValidationMessage For="() => _newRecord.Treatment" />
                        </div>
                    </div>
                    <div class="row">
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Veterinarian</label>
                            <InputText class="form-control" @bind-Value="_newRecord.VeterinarianName" />
                            <ValidationMessage For="() => _newRecord.VeterinarianName" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Date</label>
                            <InputDate class="form-control" @bind-Value="_newRecord.Date" />
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="_newRecord.Notes" />
                    </div>
                    <div class="d-flex gap-2">
                        <button type="submit" class="btn btn-primary">Save</button>
                        <button type="button" class="btn btn-secondary" @onclick="() => _showAddRecord = false">Cancel</button>
                    </div>
                </EditForm>
            </div>
        </div>
    }

    @if (_patient.MedicalRecords.Count == 0)
    {
        <p class="text-muted">No medical records yet.</p>
    }
    else
    {
        <div class="list-group">
            @foreach (var record in _patient.MedicalRecords)
            {
                <div class="list-group-item">
                    <div class="d-flex justify-content-between">
                        <h6 class="mb-1">@record.Diagnosis</h6>
                        <small class="text-muted">@record.Date.ToString("MMM d, yyyy")</small>
                    </div>
                    <p class="mb-1"><strong>Treatment:</strong> @record.Treatment</p>
                    @if (!string.IsNullOrEmpty(record.Notes))
                    {
                        <p class="mb-1"><small>@record.Notes</small></p>
                    }
                    <small class="text-muted">Dr. @record.VeterinarianName</small>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private Patient? _patient;
    private bool _showAddRecord;
    private MedicalRecord _newRecord = new();

    protected override async Task OnInitializedAsync()
    {
        _patient = await PatientService.GetByIdAsync(Id);
        if (_patient == null)
            Navigation.NavigateTo("patients");
        _newRecord.Date = DateTime.Today;
    }

    private async Task AddRecord()
    {
        _newRecord.PatientId = Id;
        await MedicalRecordService.AddAsync(_newRecord);
        _patient = await PatientService.GetByIdAsync(Id);
        _newRecord = new MedicalRecord { Date = DateTime.Today };
        _showAddRecord = false;
    }
}

@page "/appointments"
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@inject VetClinic.Services.AppointmentService AppointmentService
@inject VetClinic.Services.PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Appointments - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h1>Appointments</h1>
    <a href="appointments/new" class="btn btn-primary">New Appointment</a>
</div>

<div class="d-flex justify-content-between align-items-center mb-3">
    <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&larr; Previous Week</button>
    <h5>@_weekStart.ToString("MMM d") - @_weekStart.AddDays(5).ToString("MMM d, yyyy")</h5>
    <button class="btn btn-outline-secondary" @onclick="NextWeek">Next Week &rarr;</button>
</div>

<div class="table-responsive">
    <table class="table table-bordered table-sm">
        <thead>
            <tr>
                <th style="width:80px">Time</th>
                @for (int d = 0; d < 6; d++)
                {
                    var day = _weekStart.AddDays(d);
                    <th class="text-center">@day.ToString("ddd M/d")</th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int slot = 0; slot < 20; slot++)
            {
                var hour = 8 + slot / 2;
                var minute = (slot % 2) * 30;
                var timeLabel = new TimeOnly(hour, minute).ToString("h:mm tt");
                <tr>
                    <td class="text-nowrap small">@timeLabel</td>
                    @for (int d = 0; d < 6; d++)
                    {
                        var slotTime = _weekStart.AddDays(d).AddHours(hour).AddMinutes(minute);
                        var apt = _appointments.FirstOrDefault(a => a.ScheduledAt == slotTime);
                        if (apt != null)
                        {
                            <td class="bg-@GetStatusColor(apt.Status) bg-opacity-25 small p-1" style="cursor:pointer" @onclick="() => Navigation.NavigateTo($\"appointments/{apt.Id}/edit\")">
                                <strong>@apt.Patient.Name</strong><br/>
                                <small>@apt.Reason</small>
                            </td>
                        }
                        else
                        {
                            <td class="small p-1" style="cursor:pointer" @onclick="() => CreateAtSlot(slotTime)">
                                <span class="text-muted">Available</span>
                            </td>
                        }
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateTime _weekStart;
    private List<Appointment> _appointments = new();

    protected override async Task OnInitializedAsync()
    {
        _weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek + (int)DayOfWeek.Monday);
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        var end = _weekStart.AddDays(6);
        _appointments = await AppointmentService.GetByDateRangeAsync(_weekStart, end);
    }

    private async Task PreviousWeek()
    {
        _weekStart = _weekStart.AddDays(-7);
        await LoadAppointments();
    }

    private async Task NextWeek()
    {
        _weekStart = _weekStart.AddDays(7);
        await LoadAppointments();
    }

    private void CreateAtSlot(DateTime slotTime)
    {
        Navigation.NavigateTo($"appointments/new?date={slotTime:yyyy-MM-ddTHH:mm}");
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        _ => "secondary"
    };
}

@page "/appointments/new"
@page "/appointments/{Id:int}/edit"
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@inject VetClinic.Services.AppointmentService AppointmentService
@inject VetClinic.Services.PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>@(_isEdit ? "Edit" : "New") Appointment - VetClinic</PageTitle>

<h1>@(_isEdit ? "Edit" : "New") Appointment</h1>

<div class="row">
    <div class="col-md-8">
        <EditForm Model="_appointment" OnValidSubmit="HandleSubmit" FormName="appointmentForm">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="alert alert-danger">@_error</div>
            }

            <div class="mb-3">
                <label class="form-label">Patient</label>
                <InputSelect class="form-select" @bind-Value="_appointment.PatientId">
                    <option value="0">-- Select Patient --</option>
                    @foreach (var p in _patients)
                    {
                        <option value="@p.Id">@p.Name (@p.OwnerName)</option>
                    }
                </InputSelect>
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Date & Time</label>
                    <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="_appointment.ScheduledAt" @bind-Value:after="CheckConflict" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Duration (minutes)</label>
                    <InputNumber class="form-control" @bind-Value="_appointment.DurationMinutes" @bind-Value:after="CheckConflict" />
                </div>
            </div>

            @if (_hasConflict)
            {
                <div class="alert alert-warning">⚠️ This time slot conflicts with an existing appointment.</div>
            }

            <div class="mb-3">
                <label class="form-label">Reason</label>
                <InputText class="form-control" @bind-Value="_appointment.Reason" />
                <ValidationMessage For="() => _appointment.Reason" />
            </div>

            @if (_isEdit)
            {
                <div class="mb-3">
                    <label class="form-label">Status</label>
                    <InputSelect class="form-select" @bind-Value="_appointment.Status">
                        @foreach (var s in Enum.GetValues<AppointmentStatus>())
                        {
                            <option value="@s">@s</option>
                        }
                    </InputSelect>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Notes</label>
                <InputTextArea class="form-control" @bind-Value="_appointment.Notes" />
            </div>

            <div class="d-flex gap-2">
                <button type="submit" class="btn btn-primary" disabled="@_hasConflict">@(_isEdit ? "Update" : "Create") Appointment</button>
                <a href="appointments" class="btn btn-secondary">Cancel</a>
            </div>
        </EditForm>
    </div>
</div>

@code {
    [Parameter] public int? Id { get; set; }
    [SupplyParameterFromQuery(Name = "date")] public string? DateParam { get; set; }

    private Appointment _appointment = new() { DurationMinutes = 30 };
    private List<Patient> _patients = new();
    private bool _isEdit => Id.HasValue;
    private bool _hasConflict;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        _patients = await PatientService.GetAllAsync();

        if (_isEdit)
        {
            var existing = await AppointmentService.GetByIdAsync(Id!.Value);
            if (existing != null)
                _appointment = existing;
            else
                Navigation.NavigateTo("appointments");
        }
        else if (!string.IsNullOrEmpty(DateParam) && DateTime.TryParse(DateParam, out var dt))
        {
            _appointment.ScheduledAt = dt;
        }
        else
        {
            _appointment.ScheduledAt = DateTime.Today.AddHours(9);
        }
    }

    private async Task CheckConflict()
    {
        if (_appointment.ScheduledAt != default)
        {
            _hasConflict = await AppointmentService.HasConflictAsync(
                _appointment.ScheduledAt, _appointment.DurationMinutes, _isEdit ? Id : null);
        }
    }

    private async Task HandleSubmit()
    {
        if (_appointment.PatientId == 0)
        {
            _error = "Please select a patient.";
            return;
        }

        _hasConflict = await AppointmentService.HasConflictAsync(
            _appointment.ScheduledAt, _appointment.DurationMinutes, _isEdit ? Id : null);

        if (_hasConflict)
        {
            _error = "Time slot conflict. Please choose a different time.";
            return;
        }

        if (_isEdit)
            await AppointmentService.UpdateAsync(_appointment);
        else
            await AppointmentService.CreateAsync(_appointment);

        Navigation.NavigateTo("appointments");
    }
}

