@page "/billing"
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@inject VetClinic.Services.InvoiceService InvoiceService
@inject NavigationManager Navigation

<PageTitle>Billing - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h1>Invoices</h1>
    <a href="billing/new" class="btn btn-primary">New Invoice</a>
</div>

<div class="mb-3">
    <div class="btn-group" role="group">
        <button class="btn @(_filter == null ? "btn-primary" : "btn-outline-primary")" @onclick="() => FilterBy(null)">All</button>
        <button class="btn @(_filter == InvoiceStatus.Pending ? "btn-primary" : "btn-outline-primary")" @onclick="() => FilterBy(InvoiceStatus.Pending)">Pending</button>
        <button class="btn @(_filter == InvoiceStatus.Paid ? "btn-primary" : "btn-outline-primary")" @onclick="() => FilterBy(InvoiceStatus.Paid)">Paid</button>
        <button class="btn @(_filter == InvoiceStatus.Overdue ? "btn-primary" : "btn-outline-primary")" @onclick="() => FilterBy(InvoiceStatus.Overdue)">Overdue</button>
    </div>
</div>

@if (_loading)
{
    <div class="text-center"><div class="spinner-border" role="status"></div></div>
}
else if (_invoices.Count == 0)
{
    <p class="text-muted">No invoices found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>#</th>
                    <th>Patient</th>
                    <th>Date</th>
                    <th>Due Date</th>
                    <th>Total</th>
                    <th>Status</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var invoice in _invoices)
                {
                    <tr>
                        <td>@invoice.Id</td>
                        <td>@invoice.Patient.Name</td>
                        <td>@invoice.CreatedAt.ToString("MMM d, yyyy")</td>
                        <td>@invoice.DueDate.ToString("MMM d, yyyy")</td>
                        <td>$@invoice.TotalAmount.ToString("N2")</td>
                        <td><span class="badge bg-@GetStatusColor(invoice.Status)">@invoice.Status</span></td>
                        <td><a href="billing/@invoice.Id" class="btn btn-sm btn-outline-primary">View</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private bool _loading = true;
    private InvoiceStatus? _filter;
    private List<Invoice> _invoices = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoices();
    }

    private async Task FilterBy(InvoiceStatus? status)
    {
        _filter = status;
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        _loading = true;
        _invoices = await InvoiceService.GetAllAsync(_filter);
        _loading = false;
    }

    private string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Overdue => "danger",
        InvoiceStatus.Cancelled => "secondary",
        _ => "secondary"
    };
}

@page "/billing/new"
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@inject VetClinic.Services.InvoiceService InvoiceService
@inject VetClinic.Services.PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>New Invoice - VetClinic</PageTitle>

<h1>New Invoice</h1>

<div class="row">
    <div class="col-md-10">
        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="alert alert-danger">@_error</div>
        }

        <div class="mb-3">
            <label class="form-label">Patient</label>
            <select class="form-select" @bind="_patientId">
                <option value="0">-- Select Patient --</option>
                @foreach (var p in _patients)
                {
                    <option value="@p.Id">@p.Name (@p.OwnerName)</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Due Date</label>
            <input type="date" class="form-control" @bind="_dueDate" />
        </div>

        <h4>Line Items</h4>
        <table class="table">
            <thead>
                <tr>
                    <th>Description</th>
                    <th style="width:100px">Qty</th>
                    <th style="width:130px">Unit Price</th>
                    <th style="width:130px">Amount</th>
                    <th style="width:60px"></th>
                </tr>
            </thead>
            <tbody>
                @for (int i = 0; i < _lineItems.Count; i++)
                {
                    var index = i;
                    <tr>
                        <td><input class="form-control form-control-sm" @bind="_lineItems[index].Description" /></td>
                        <td><input type="number" class="form-control form-control-sm" @bind="_lineItems[index].Quantity" @bind:after="() => RecalculateItem(index)" min="1" /></td>
                        <td><input type="number" step="0.01" class="form-control form-control-sm" @bind="_lineItems[index].UnitPrice" @bind:after="() => RecalculateItem(index)" /></td>
                        <td class="align-middle">$@_lineItems[index].Amount.ToString("N2")</td>
                        <td><button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveItem(index)">✕</button></td>
                    </tr>
                }
            </tbody>
        </table>

        <button class="btn btn-outline-success btn-sm mb-3" @onclick="AddItem">+ Add Line Item</button>

        <div class="text-end mb-3">
            <h4>Total: $@_total.ToString("N2")</h4>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="HandleSubmit">Create Invoice</button>
            <a href="billing" class="btn btn-secondary">Cancel</a>
        </div>
    </div>
</div>

@code {
    private List<Patient> _patients = new();
    private int _patientId;
    private DateTime _dueDate = DateTime.Today.AddDays(30);
    private List<InvoiceLineItem> _lineItems = new() { new InvoiceLineItem { Quantity = 1 } };
    private decimal _total;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        _patients = await PatientService.GetAllAsync();
    }

    private void AddItem()
    {
        _lineItems.Add(new InvoiceLineItem { Quantity = 1 });
    }

    private void RemoveItem(int index)
    {
        if (_lineItems.Count > 1)
        {
            _lineItems.RemoveAt(index);
            RecalculateTotal();
        }
    }

    private void RecalculateItem(int index)
    {
        _lineItems[index].Amount = _lineItems[index].Quantity * _lineItems[index].UnitPrice;
        RecalculateTotal();
    }

    private void RecalculateTotal()
    {
        _total = _lineItems.Sum(li => li.Amount);
    }

    private async Task HandleSubmit()
    {
        if (_patientId == 0)
        {
            _error = "Please select a patient.";
            return;
        }

        if (_lineItems.All(li => string.IsNullOrWhiteSpace(li.Description)))
        {
            _error = "Please add at least one line item with a description.";
            return;
        }

        var invoice = new Invoice
        {
            PatientId = _patientId,
            DueDate = _dueDate,
            LineItems = _lineItems.Where(li => !string.IsNullOrWhiteSpace(li.Description)).ToList()
        };

        await InvoiceService.CreateAsync(invoice);
        Navigation.NavigateTo("billing");
    }
}

@page "/billing/{Id:int}"
@attribute [Authorize]

@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@inject VetClinic.Services.InvoiceService InvoiceService
@inject NavigationManager Navigation

<PageTitle>Invoice Details - VetClinic</PageTitle>

@if (_invoice == null)
{
    <div class="text-center"><div class="spinner-border" role="status"></div></div>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-4">
        <h1>Invoice #@_invoice.Id</h1>
        <span class="badge bg-@GetStatusColor(_invoice.Status) fs-5">@_invoice.Status</span>
    </div>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="card">
                <div class="card-body">
                    <p><strong>Patient:</strong> @_invoice.Patient.Name</p>
                    <p><strong>Created:</strong> @_invoice.CreatedAt.ToString("MMM d, yyyy")</p>
                    <p><strong>Due Date:</strong> @_invoice.DueDate.ToString("MMM d, yyyy")</p>
                    @if (_invoice.Appointment != null)
                    {
                        <p><strong>Appointment:</strong> @_invoice.Appointment.ScheduledAt.ToString("MMM d, yyyy h:mm tt")</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <h4>Line Items</h4>
    <table class="table">
        <thead>
            <tr>
                <th>Description</th>
                <th class="text-end">Qty</th>
                <th class="text-end">Unit Price</th>
                <th class="text-end">Amount</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _invoice.LineItems)
            {
                <tr>
                    <td>@item.Description</td>
                    <td class="text-end">@item.Quantity</td>
                    <td class="text-end">$@item.UnitPrice.ToString("N2")</td>
                    <td class="text-end">$@item.Amount.ToString("N2")</td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <td colspan="3" class="text-end"><strong>Total</strong></td>
                <td class="text-end"><strong>$@_invoice.TotalAmount.ToString("N2")</strong></td>
            </tr>
        </tfoot>
    </table>

    <h4>Payments</h4>
    @if (_invoice.Payments.Count == 0)
    {
        <p class="text-muted">No payments recorded.</p>
    }
    else
    {
        <table class="table table-sm">
            <thead>
                <tr><th>Date</th><th>Method</th><th class="text-end">Amount</th></tr>
            </thead>
            <tbody>
                @foreach (var payment in _invoice.Payments)
                {
                    <tr>
                        <td>@payment.PaidAt.ToString("MMM d, yyyy h:mm tt")</td>
                        <td>@payment.Method</td>
                        <td class="text-end">$@payment.Amount.ToString("N2")</td>
                    </tr>
                }
            </tbody>
            <tfoot>
                <tr>
                    <td colspan="2" class="text-end"><strong>Total Paid</strong></td>
                    <td class="text-end"><strong>$@_invoice.Payments.Sum(p => p.Amount).ToString("N2")</strong></td>
                </tr>
            </tfoot>
        </table>
    }

    @if (_invoice.Status != InvoiceStatus.Paid && _invoice.Status != InvoiceStatus.Cancelled)
    {
        <div class="card mt-3">
            <div class="card-header"><strong>Record Payment</strong></div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Amount</label>
                        <input type="number" step="0.01" class="form-control" @bind="_paymentAmount" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Method</label>
                        <select class="form-select" @bind="_paymentMethod">
                            @foreach (var m in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@m">@m</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-4 mb-2 d-flex align-items-end">
                        <button class="btn btn-success" @onclick="RecordPayment">Record Payment</button>
                    </div>
                </div>
            </div>
        </div>
